#include <sys/wait.h>

typedef struct {
    char *cmd;
    char *infile;
    char *outfile;
    int append;
} Command;

Command parse_redirections(char *line) {
    Command c = {NULL, NULL, NULL, 0};
    char *token = strtok(line, " ");
    char cmd_buf[256] = "";
    while (token) {
        if (strcmp(token, "<") == 0) {
            token = strtok(NULL, " ");
            c.infile = token;
        } else if (strcmp(token, ">>") == 0) {
            token = strtok(NULL, " ");
            c.outfile = token;
            c.append = 1;
        } else if (strcmp(token, ">") == 0) {
            token = strtok(NULL, " ");
            c.outfile = token;
        } else {
            if (strlen(cmd_buf) > 0) strcat(cmd_buf, " ");
            strcat(cmd_buf, token);
        }
        token = strtok(NULL, " ");
    }
    c.cmd = strdup(cmd_buf);
    return c;
}

void execute_with_redirections(Command *c) {
    printf("CMD: %s\n", c->cmd);
    if (c->infile)
        printf("REDIR: stdin < %s\n", c->infile);
    if (c->outfile) {
        if (c->append)
            printf("REDIR: stdout >> %s\n", c->outfile);
        else
            printf("REDIR: stdout > %s\n", c->outfile);
    }

    pid_t pid = fork();
    if (pid == 0) {
        if (c->infile) {
            int fd = open(c->infile, O_RDONLY);
            if (fd >= 0) {
                dup2(fd, STDIN_FILENO);
                close(fd);
            }
        }
        if (c->outfile) {
            int flags = O_WRONLY | O_CREAT;
            flags |= c->append ? O_APPEND : O_TRUNC;
            int fd = open(c->outfile, flags, 0644);
            if (fd >= 0) {
                dup2(fd, STDOUT_FILENO);
                close(fd);
            }
        }
        printf("[exec: %s]\n", c->cmd);
        exit(0);
    }
    int status;
    waitpid(pid, &status, 0);
    printf("EXIT: %d\n", WEXITSTATUS(status));
}

int main(void) {
    char line1[] = "cat < input.txt";
    char line2[] = "echo hello > output.txt";
    char line3[] = "logger msg >> log.txt";

    Command c1 = parse_redirections(line1);
    Command c2 = parse_redirections(line2);
    Command c3 = parse_redirections(line3);

